    {
      "name": "basic_app_request",
      "input": {
        "user_input": "I want to build an app for cleaning services"
      },
      "output": {
        "questions": [
          "What stage is the project in?",
          "Do you have mockups or designs?",
          "Is this the first task, or part of a series of challenges?"
        ],
        "scope_suggestions": [
          "Focus on user interface design",
          "Develop a prototype",
          "Conduct user testing"
        ]
      },
      "notes": "Validates basic scoping dialogue initiation."
    },
    {
      "name": "project_stage_clarification",
      "input": {
        "user_input": "I have a design ready"
      },
      "output": {
        "questions": [
          "What features are included in the design?",
          "Is this for development or testing?"
        ],
        "scope_suggestions": [
          "Develop the app based on the design",
          "Test the design with users"
        ]
      },
      "notes": "Checks if the agent can clarify project stage."
    },
    {
      "name": "no_mockups",
      "input": {
        "user_input": "I want to build an app but have no designs"
      },
      "output": {
        "questions": [
          "What functionalities do you envision?",
          "Do you have any examples of similar apps?"
        ],
        "scope_suggestions": [
          "Start with brainstorming features",
          "Create wireframes"
        ]
      },
      "notes": "Tests the agent's ability to handle lack of designs."
    },
    {
      "name": "broad_goal",
      "input": {
        "user_input": "I want to innovate in healthcare"
      },
      "output": {
        "questions": [
          "Can you specify which area of healthcare?",
          "What is your primary goal?"
        ],
        "scope_suggestions": [
          "Focus on telehealth solutions",
          "Develop a health tracking app"
        ]
      },
      "notes": "Validates handling of vague user goals."
    },
    {
      "name": "iterative_scope_reassessment",
      "input": {
        "user_input": "I want to create a platform for data science competitions"
      },
      "output": {
        "questions": [
          "What features do you want to include?",
          "Is this a standalone platform or part of an existing system?"
        ],
        "scope_suggestions": [
          "Include user submission features",
          "Add a leaderboard"
        ]
      },
      "notes": "Tests the iterative nature of scope reassessment."
    },
    {
      "name": "adversarial_case_no_feedback",
      "input": {
        "user_input": "I want to build something innovative"
      },
      "output": {
        "questions": [
          "Can you provide more details?",
          "What industry are you focusing on?"
        ],
        "scope_suggestions": []
      },
      "notes": "Checks the agent's response to overly vague input."
    },
    {
      "name": "adversarial_case_conflicting_goals",
      "input": {
        "user_input": "I want to build an app for cleaning services but also want to include a marketplace"
      },
      "output": {
        "questions": [
          "Which goal is more important?",
          "Can you prioritize the features?"
        ],
        "scope_suggestions": [
          "Focus on cleaning services first",
          "Consider a phased approach"
        ]
      },
      "notes": "Tests how the agent handles conflicting user goals."
    },
